def cache_result(ttl: int = DEFAULT_CACHE_TTL, key_prefix: str = ""):
    """Caching decorator for expensive database queries."""
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            raw_key = f"{key_prefix}{func.__name__}:{json.dumps(args, sort_keys=True, default=str)}:{json.dumps(kwargs, sort_keys=True, default=str)}"
            cache_key = f"{CACHE_PREFIX}{_sanitize_key(raw_key)}"

            try:
                cached = redis_client.get(cache_key)
                if cached is not None:
                    app.logger.debug(f"Cache hit for {func.__name__}")
                    return json.loads(cached)
            except (redis.RedisError, json.JSONDecodeError) as e:
                app.logger.warning(f"Cache read error, executing function: {e}")

            result = func(*args, **kwargs)

            try:
                redis_client.set(cache_key, json.dumps(result, default=str), ex=ttl)
            except (redis.RedisError, json.JSONEncodeError) as e:
                app.logger.warning(f"Cache write error: {e}")

            return result
        return wrapper
    return decorator


def invalidate_cache(func_name: str, *args, **kwargs):
    raw_key = f"{func_name}:{json.dumps(args, sort_keys=True, default=str)}:{json.dumps(kwargs, sort_keys=True, default=str)}"
    cache_key = f"{CACHE_PREFIX}{_sanitize_key(raw_key)}"
    try:
        redis_client.delete(cache_key)
        return True
    except redis.RedisError as e:
        app.logger.error(f"Failed to invalidate cache: {e}")
        return False


